PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE clients (     email         TEXT PRIMARY KEY,     fname         TEXT NOT NULL,     lname         TEXT NOT NULL,     isCoach       INTEGER NOT NULL DEFAULT 0,     pw            TEXT NOT NULL DEFAULT '',     unitDefault   TEXT NOT NULL DEFAULT 'imperial',     accessCode    TEXT UNIQUE,     emailConfirmed INTEGER NOT NULL DEFAULT 0 , coachedBy TEXT REFERENCES clients(email) ON UPDATE CASCADE ON DELETE SET NULL, timezone TEXT DEFAULT 'UTC');
CREATE TABLE [workouts] ("id" text PRIMARY KEY,"data" text, workoutName TEXT, createdBy   TEXT REFERENCES clients(email), createdAt  TEXT);
CREATE TABLE [history] ("id" text PRIMARY KEY,"dateTime" text,"clientId" text,"workoutId" text,"exerciseId" text,"set" integer,"weight" integer,"weightUnit" text,"note" text, rpe      REAL, reps     INTEGER, syncedAt TEXT, countType   TEXT, prescribed  REAL, prescribedMax REAL, unit        TEXT, coachNotes TEXT, skipped INTEGER DEFAULT 0);
CREATE TABLE [calendars] ("id" text PRIMARY KEY,"date" text,"clientId" text,"workoutId" text,"completed" integer);
CREATE TABLE scheduled_workouts (   id            TEXT PRIMARY KEY,   clientEmail   TEXT NOT NULL REFERENCES clients(email),   workoutId     TEXT NOT NULL,   workoutName   TEXT NOT NULL,   scheduledDate TEXT NOT NULL,   status        TEXT NOT NULL DEFAULT 'scheduled',   skipReason    TEXT,   completedAt   TEXT,   originalDate  TEXT,   copiedFrom    TEXT REFERENCES scheduled_workouts(id) );
CREATE TABLE refresh_tokens (   token TEXT PRIMARY KEY,   client_id TEXT NOT NULL REFERENCES clients(email) ON DELETE CASCADE,   expires_at INTEGER NOT NULL );
CREATE TABLE password_reset_codes (   client_id TEXT PRIMARY KEY REFERENCES clients(email) ON DELETE CASCADE,   code TEXT NOT NULL,   expires_at INTEGER NOT NULL );
CREATE TABLE coach_exercise_notes (     id           TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),     clientEmail  TEXT NOT NULL,     exerciseId   TEXT NOT NULL,     note         TEXT NOT NULL,     updatedAt    TEXT NOT NULL DEFAULT (datetime('now')),     UNIQUE(clientEmail, exerciseId) );
